namespace Dataphyre\Panel;

/**
 * Emits the presentation-scale Panel stylesheet.
 *
 * This asset is the broad layout layer for dashboards, custom pages, tables,
 * command surfaces, modal states, generated templates, dark/system modes, and
 * responsive breakpoints. It is returned as a static string and depends on the
 * renderer to place it after core/component CSS so its layout refinements win.
 */
trait PanelRendererAssetsPresentationCss {
	/**
	 * Returns the presentation layout stylesheet for rich panel surfaces.
	 *
	 * The block defines full-width content constraints, dashboard cards, template
	 * sections, command palette states, modal/drawer behavior, responsive table and
	 * action layouts, and dark/system overrides. It performs no escaping or
	 * interpolation because dynamic values are supplied through CSS variables and
	 * renderer-owned attributes.
	 *
	 * @return string CSS emitted for presentation-oriented panel layouts.
	 */
	private static function presentationCss(): string {
		return <<<'CSS'
.dp-panel{--dp-panel-pad-bottom:34px}
:root{--dp-page-max:1720px;--dp-shell-gap:18px;--dp-present-radius:18px;--dp-present-radius-sm:12px;--dp-present-shadow:0 18px 44px rgba(15,23,42,.075);--dp-present-shadow-soft:0 10px 26px rgba(15,23,42,.055);--dp-present-ring:0 0 0 4px color-mix(in srgb,var(--dp-primary-600,#2563eb) 14%,transparent)}
html{background:var(--dp-body_bg,#f5f7fa)!important}
body{min-height:100%;background:linear-gradient(180deg,color-mix(in srgb,var(--dp-body_bg,#f5f7fa) 82%,#fff) 0,var(--dp-body_bg,#f5f7fa) 420px,var(--dp-body_bg,#f5f7fa) 100%)!important;color:var(--dp-text)!important}
body[data-dp-theme-mode="dark"]{background:linear-gradient(180deg,#0d1524 0,#0f1726 420px,#101828 100%)!important}
.dp-panel{--dp-panel-content-width:min(100%,var(--dp-page-max));--dp-panel-content-max:var(--dp-page-max);--dp-panel-content-margin:auto;width:100%;max-width:none!important;margin-inline:0!important;padding:18px clamp(16px,2.2vw,32px) 34px!important}
.dp-panel-page-width-constrained{--dp-panel-content-width:min(100%,var(--dp-page-max,1720px));--dp-panel-content-max:var(--dp-page-max,1720px);--dp-panel-content-margin:auto}
.dp-panel-page-width-fluid{--dp-panel-content-width:100%;--dp-panel-content-max:none;--dp-panel-content-margin:0}
.dp-panel-page-width-compact{--dp-panel-content-width:min(100%,1280px);--dp-panel-content-max:1280px;--dp-panel-content-margin:auto}
.dp-panel-with-sidebar{max-width:none!important;grid-template-columns:minmax(236px,272px) minmax(0,1fr)!important;column-gap:18px!important}
.dp-panel-main-region{display:grid;align-content:start;gap:14px;min-width:0;width:var(--dp-panel-content-width,100%);max-width:var(--dp-panel-content-max,none);margin-inline:var(--dp-panel-content-margin,0)}
.dp-panel-with-sidebar .dp-panel-main-region{width:100%;max-width:none;margin-inline:0}
.dp-panel[data-dp-panel-kind="dashboard"] .dp-panel-main-region,.dp-panel[data-dp-panel-kind="custom_page"] .dp-panel-main-region{gap:16px}
.dp-panel[data-dp-panel-kind="dashboard"] .dp-panel-widgets,.dp-panel[data-dp-panel-kind="custom_page"] .dp-panel-widgets{grid-template-columns:repeat(auto-fit,minmax(250px,1fr))!important;align-items:stretch}
.dp-panel[data-dp-panel-kind="dashboard"] .dp-panel-global-search{display:grid!important;grid-template-columns:minmax(280px,1fr) auto auto!important;gap:10px!important;align-items:center!important;margin:0!important;padding:14px!important;border:1px solid var(--dp-border_soft)!important;border-radius:20px!important;background:color-mix(in srgb,var(--dp-surface) 92%,var(--dp-surface_muted))!important;box-shadow:var(--dp-present-shadow-soft)!important}
