.dp-panel[data-dp-panel-kind="dashboard"] .dp-panel-global-search .dp-panel-button{height:48px!important;min-height:48px!important;min-width:126px!important}
.dp-panel[data-dp-panel-kind="dashboard"] .dp-panel-search-results{display:grid!important;gap:10px!important;margin:0!important}
.dp-panel[data-dp-panel-kind="dashboard"] .dp-panel-search-results>header,.dp-panel[data-dp-panel-kind="dashboard"] .dp-panel-nav-group>header{display:flex!important;align-items:center!important;justify-content:space-between!important;gap:12px!important;margin:0!important}
.dp-panel[data-dp-panel-kind="dashboard"] .dp-panel-search-results>header h2,.dp-panel[data-dp-panel-kind="dashboard"] .dp-panel-nav-group>header h2{margin:0!important;font-size:13px!important;font-weight:920!important;letter-spacing:.065em!important;text-transform:uppercase!important;color:var(--dp-text_muted)!important}
.dp-panel[data-dp-panel-kind="dashboard"] .dp-panel-search-results>header span,.dp-panel[data-dp-panel-kind="dashboard"] .dp-panel-nav-group>header span{display:inline-flex!important;align-items:center!important;min-height:28px!important;border:1px solid var(--dp-border_soft)!important;border-radius:999px!important;background:var(--dp-surface_muted)!important;color:var(--dp-text_muted)!important;padding:4px 10px!important;font-size:11px!important;font-weight:900!important}
.dp-panel[data-dp-panel-kind="dashboard"] .dp-panel-search-result{display:grid!important;gap:4px!important;min-height:74px!important;padding:14px 16px!important;text-decoration:none!important;transition:transform .14s ease,border-color .14s ease,box-shadow .14s ease}
.dp-panel[data-dp-panel-kind="dashboard"] .dp-panel-search-result:hover{transform:translateY(-1px);border-color:color-mix(in srgb,var(--dp-primary-600,#2563eb) 34%,var(--dp-border))!important;box-shadow:0 16px 36px rgba(15,23,42,.09)!important}
.dp-panel[data-dp-panel-kind="dashboard"] .dp-panel-search-result span{font-size:10px!important;font-weight:920!important;letter-spacing:.075em!important;text-transform:uppercase!important;color:var(--dp-text_muted)!important}
.dp-panel[data-dp-panel-kind="dashboard"] .dp-panel-search-result strong{color:var(--dp-text)!important;font-size:16px!important;font-weight:900!important}
