.dp-panel[data-dp-panel-kind="dashboard"] .dp-panel-nav-group .dp-panel-grid{grid-template-columns:repeat(auto-fit,minmax(230px,1fr))!important;gap:10px!important}
.dp-panel-page-table{grid-template-columns:minmax(0,1fr)!important}
.dp-panel-page-table>*{min-width:0!important;max-width:100%!important}
.dp-panel-page-table>.dp-panel-table-scroll{width:100%!important;max-width:100%!important;min-width:0!important;overflow:auto!important}
.dp-panel[data-dp-panel-kind="dashboard"] .dp-panel-nav-card{display:grid!important;grid-template-columns:auto minmax(0,1fr)!important;grid-template-areas:"icon title" "icon desc"!important;align-items:center!important;gap:4px 12px!important;min-height:86px!important;padding:14px!important;border-radius:16px!important;text-decoration:none!important;box-shadow:none!important;transition:transform .14s ease,border-color .14s ease,background .14s ease,box-shadow .14s ease}
