.dp-panel{--dp-polish-shadow:0 18px 46px color-mix(in srgb,var(--dp-text) 8%,transparent);--dp-polish-shadow-lift:0 24px 68px color-mix(in srgb,var(--dp-text) 12%,transparent);--dp-polish-hairline:color-mix(in srgb,var(--dp-border) 74%,transparent)}
.dp-panel-main-region{display:grid!important;align-content:start!important;gap:14px!important}
.dp-panel-main-region>header{overflow:hidden!important}
.dp-panel-main-region>header:after{content:"";position:absolute;left:18px;right:18px;bottom:0;height:1px;background:linear-gradient(90deg,transparent,color-mix(in srgb,var(--dp-primary-600,#2563eb) 42%,transparent),color-mix(in srgb,var(--dp-info-600,#0891b2) 28%,transparent),transparent);opacity:.72;pointer-events:none}
.dp-panel-heading-row{position:relative!important;z-index:1!important;align-items:center!important}
