.dp-panel-heading-tools{padding:0!important;border-radius:0!important;background:transparent!important}
.dp-panel-live-control,.dp-panel-theme-toggle{box-shadow:inset 0 1px 0 color-mix(in srgb,#fff 16%,transparent),0 9px 24px color-mix(in srgb,var(--dp-text) 6%,transparent)!important}
