.dp-panel-card:hover,.dp-panel-widget:hover,.dp-panel-summary:hover,.dp-panel-show-field:hover,.dp-panel-alert-card:hover,.dp-panel-insight:hover,.dp-panel-link:hover,.dp-panel-contact:hover,.dp-panel-location:hover,.dp-panel-item:hover,.dp-panel-total:hover,.dp-panel-approval:hover,.dp-panel-task:hover,.dp-panel-change:hover,.dp-panel-payment:hover,.dp-panel-shipment:hover,.dp-panel-message:hover,.dp-panel-note:hover{transform:translateY(-1px)!important;border-color:color-mix(in srgb,var(--dp-primary-600,#2563eb) 22%,var(--dp-border))!important;box-shadow:var(--dp-polish-shadow-lift)!important}
.dp-panel-widget,.dp-panel-summary{position:relative!important;overflow:hidden!important}
